import{_ as o,c as a,a3 as c,o as d}from"./chunks/framework.VX8o9GSp.js";const m=JSON.parse('{"title":"多服务共享单一域名的奥秘","description":"","frontmatter":{"date":"2024-10-08T00:00:00.000Z","tags":["域名"],"categories":["计算机"]},"headers":[],"relativePath":"2024/10/多服务共享单一域名的奥秘.md","filePath":"2024/10/多服务共享单一域名的奥秘.md","lastUpdated":1728746529000}'),t={name:"2024/10/多服务共享单一域名的奥秘.md"};function p(r,e,s,n,_,i){return d(),a("div",null,e[0]||(e[0]=[c('<h1 id="多服务共享单一域名的奥秘" tabindex="-1">多服务共享单一域名的奥秘 <a class="header-anchor" href="#多服务共享单一域名的奥秘" aria-label="Permalink to &quot;多服务共享单一域名的奥秘&quot;">​</a></h1><p>一个域名通常只能解析到一个 IP 地址或服务。但你可以通过使用子域名来让同一域名同时服务于不同服务，如 <code>www.example.com</code> 用于网页服务和 <code>files.example.com</code> 用于对象存储服务。</p><p>一级域名位于域名最右边，如 <code>.com</code>，二级域名位于一级域名的左边，如 <code>example</code>。从云服务商或域名注册商处购买的通常是二级域名，你可以在二级域名下创建任意数量的三级域名。</p><p>比如 <code>www.pan.baidu.com</code> 是四级域名，顶级到最低级分别是 <code>.com</code>、<code>baidu</code>、<code>pan</code> 和 <code>www</code>。你可以自定义三级域名，但需在 DNS 设置中添加记录指向相应IP地址。</p><p>理论上你可以在二级域名下创建无限多个三级域名，但在管理上，通常只建议根据需要创建。</p><p>通过子域名可以实现一个二级域名解析到博客网站，同时另一个子域名解析到对象存储。你需要将二级域名指向博客网站，再设置一个三级域名指向对象存储。</p><p>对象存储的静态网站功能允许托管由静态文件组成的网站，但无法处理服务器端的动态内容。你可以使用对象存储服务来搭建静态网站，只需创建存储桶、上传文件并启用静态网站功能即可。如果你的网站需要动态内容处理，则需要使用云服务器或其他托管服务。</p>',7)]))}const f=o(t,[["render",p]]);export{m as __pageData,f as default};
